var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"며칠 뒤","JPN":"数日後","ENG":"A few days later","TWN":"幾天後","SCN":"几天后","DEU":"A few days later","FRA":"A few days later"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 재건 도시 <color=#ffd34c>ARC-NL1</color>\\n구 네덜란드, 암스테르담","JPN":"管理局再建都市<color=#ffd34c>ARC-NL1</color>\\n旧オランダ、アムステルダム","ENG":"[[","TWN":"管理局重建城市<color=#ffd34c>ARC-NL1</color>\\n舊荷蘭 阿姆斯特丹","SCN":"管理局重建城市<color=#ffd34c>ARC-NL1</color>\\n旧荷兰，阿姆斯特丹","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"subtitle","speaker":null,"text":{"KOREA":"다국적 합자 대침식 연구소 – 퓨처 앳 워\\n<color=#ffd34c>제3지부 항공 우주 연구소</color>","JPN":"多国籍合資対侵食戦研究所 - フューチャーアットウォー\\n<color=#ffd34c>第3支部航空宇宙研究所</color>","ENG":"[[","TWN":"跨國合資反侵蝕研究所-天啟兵器\\n<color=#ffd34c>第三分部航空航太研究所</color>","SCN":"跨国合资反侵蚀研究所-天启兵器\\n<color=#ffd34c>第三分部航空航天研究所</color>","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……아무도 안 계세요?","JPN":"……すみませーん。","ENG":"...Hello? Is anyone here?","TWN":"……沒有人嗎？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"메이시 박사님…? 망원 렌즈 때문에 찾아왔는데요……?","JPN":"メイシ博士……？　望遠レンズのことで来たんですけど……？","ENG":"Dr. Macy...? I came to talk about the Zoom Lens...","TWN":"梅西博士……我想問你望遠鏡頭的事……"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"뭐야, 아무도 없나 본데?","JPN":"なんだ、誰もいないのか？","ENG":"Huh? Looks like no one's here.","TWN":"搞什麼？看起來沒有人呢？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그 박사라는 사람, 할망구가 여기 오면 만날 수 있다고 하지 않았어?","JPN":"ババァが、ここに来れば博士って人に会えるって言ってなかった？","ENG":"Didn't that old hag say we'd find the doc here?","TWN":"瘋婆子不是說來這就能見到那個博士嗎？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그러게요, 나중에 다시 와야 하나?","JPN":"そうだけど、後でまた来た方がいいのかな？","ENG":"Yeah... Maybe we should come back later.","TWN":"是啊，難道要下次再來嗎？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그나저나 엄청나네요.","JPN":"それにしてもすごいわね。","ENG":"But still, this place is incredible.","TWN":"不過真是厲害啊。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"뭔지 모를 기계 장치들이 잔뜩 쌓여있어요.","JPN":"なんだかよくわからない機械装置がいっぱい。","ENG":"It's packed with all kinds of strange machinery.","TWN":"不知名的機械裝置堆積如山。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"설마, 여기 있는 것들 전부 그 메이시 박사라는 분이 만든 걸까요?","JPN":"まさか、ここにあるもの全部、そのメイシ博士っていう人が作ったのかしら？","ENG":"You think all this stuff was made by Dr. Macy?","TWN":"難道，這裡所有的東西都是那個梅西博士製造的嗎？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"글쎄다? 할망구 말로는 여기가 그 유명한 퓨처 앳 워 연구소 중 하나라고 했으니까.","JPN":"さあ？　ババァはここがあの有名なフューチャーアットウォーの研究所の一つだって言ってたからな。","ENG":"Who knows? The old hag said this was one of the Future-at-War labs.","TWN":"誰知道呢？瘋婆子說這裡是著名的天啟兵器研究所之一。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"퓨처 앳 워라면 엄마한테 들은 적이 있어요.","JPN":"フューチャーアットウォーなら、お母さんから聞いたことがあるわ。","ENG":"Future-at-War? Oh, I've heard of that. My mom used to talk about it.","TWN":"如果是天啟兵器，我聽媽媽說過。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"여긴 천재 중의 천재만 입사할 수 있는 곳이라면서요?","JPN":"天才の中の天才しか入社できないところだって。","ENG":"Only super-geniuses are allowed to work here, right?","TWN":"這裡不是說只有天才中的天才能入職嗎？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이런 커다란 연구소의 소장이라면, 틀림없이 라이카보다 백배는 더 똑똑하겠죠?","JPN":"こんな大きな研究所の所長なら、きっとライカより100倍は頭がいいんだろうね？","ENG":"If she's the head of such a huge lab, she's gotta be a hundred times smarter than you. Right, Laika?","TWN":"如果是這樣一個大型研究所的所長，肯定比萊卡聰明百倍吧？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그래? 내가 들은 거랑 조금 다른데?","JPN":"どうだろうな。それに、私が聞いたのとはちょっと違うしね。","ENG":"Eh, that's not what I heard.","TWN":"是嗎？和我聽到的有點不一樣呢？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"무인 전쟁을 추구했던 초창기 퓨처 앳 워 계획은 진즉에 실패해 버렸고.","JPN":"無人戦争を追及していた初期のフューチャーアットウォー計画はとっくに失敗してて。","ENG":"The original Future-at-War program for unmanned combat failed ages ago.","TWN":"追求無人戰爭的初期天啟兵器計畫早就失敗了。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"지금까지 퓨처 앳 워에 남아있는 녀석들은 괴짜 중의 괴짜들 밖에 없다고 들었거든.","JPN":"まだフューチャーアットウォーに残ってるやつらは変人の中の変人しかいないって話だった。","ENG":"The ones still hanging around there are all weirdos among weirdos.","TWN":"我聽說現在留在天啟兵器中的傢伙都是怪胎中的怪胎。"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"괴짜라고요?","JPN":"変人？","ENG":"Weirdos?","TWN":"怪胎？"},"stage":{"bg":"HANGAR","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그래, 그 메이시 박사라는 녀석도 사실은 엄청난 괴짜일지도 모르지.","JPN":"ああ、そのメイシ博士ってやつも実はものすごい変人かもよ。","ENG":"Yeah. For all we know, Dr. Macy could be one too.","TWN":"是啊，說不定那個叫梅西的博士其實是個超級怪胎呢。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"아니, 어쩌면 터질듯한 근육질 몸매에 수염 잔뜩 난 술고래 영감탱이일지도 몰라.","JPN":"いや、もしかしたら弾けるばかりのマッチョなボディにヒゲ面の酔っ払いジジィかも。","ENG":"Or worse, some musclehead drunk with a beard.","TWN":"說不定是個滿臉鬍鬚、肌肉爆炸的老酒鬼呢。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"괴짜랑 근육질 술고래가 무슨 상관이에요.","JPN":"変人とマッチョな酔っ払いって何の関係があるの？","ENG":"What does being weird have to do with muscles and booze?","TWN":"怪胎和肌肉酒鬼有什麼關係呢。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그리고 그건 그냥 햄스워스 씨잖아요?","JPN":"それに、それってヘムズワースさんのことじゃない。","ENG":"That just sounds like Mr. Helmsworth.","TWN":"而且那不就是漢姆沃斯先生嗎？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"야, 생각해 봐. 그 영감탱이도 괴짜잖냐?","JPN":"おい、考えてみろ。あのジジィも変人だろ？","ENG":"Exactly! Think about it. He's a total weirdo too, right?","TWN":"喂，想想看。那個老頭也是個怪胎吧？"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그래서 시도 때도 없이 꼬맹이를 끌어안고, 맥주 묻은 수염을 네 얼굴에 부벼대는 거지.","JPN":"だからいつもおこちゃまを抱っこして、ビールがついたヒゲをあんたの顔にすりすりするんだ。","ENG":"That's why he keeps hugging you at random and rubbing his beer-soaked beard on your face.","TWN":"所以才會時不時地抱著你，用沾滿啤酒的鬍子蹭你的臉。"},"stage":{"bg":"HANGAR","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};